class PricingEngine {
    double finalPrice(int qty, double unitPrice, boolean premiumUser) {
        double base = qty * unitPrice;
        double disc = qty >= 50 ? 0.20 : qty >= 10 ? 0.10 : 0.0;
        double afterDisc = base * (1 - disc);
        double afterPremium = premiumUser ? afterDisc * 0.95 : afterDisc;
        return Math.max(afterPremium, 10.0);
    }
}
