// (CSVParser as above)
import org.junit.jupiter.params.*;
import org.junit.jupiter.params.provider.*;
import static org.junit.jupiter.api.Assertions.*;
import java.util.stream.*;
import java.util.*;
class CSVParserTest {
    @ParameterizedTest
    @CsvSource({
        "'a,b,c',        3, a",
        "'a,b',          2, a",
        "'single',       1, single",
        "'a,,c',         3, a"
    })
    void parseCSVLine_normalInputs(String line, int expectedFields, String firstField) {
        List<String> result = CSVParser.parseCSVLine(line);
        assertEquals(expectedFields, result.size());
        assertEquals(firstField, result.get(0));
    }

    static Stream<Arguments> quotedCases() {
        return Stream.of(
            Arguments.of("\"Smith, John\",95000",        List.of("Smith, John", "95000")),
            Arguments.of("\"Dell 27\"\" Monitor\",18999", List.of("Dell 27\" Monitor", "18999")),
            Arguments.of("\"quoted\",plain",              List.of("quoted", "plain")),
            Arguments.of("\"\",empty",                    List.of("", "empty"))
        );
    }
    @ParameterizedTest
    @MethodSource("quotedCases")
    void parseCSVLine_quotedFields(String line, List<String> expected) {
        assertEquals(expected, CSVParser.parseCSVLine(line));
    }

    @ParameterizedTest
    @NullAndEmptySource
    void parseCSVLine_nullOrEmpty_returnsEmptyOrSingleEmpty(String line) {
        List<String> r = CSVParser.parseCSVLine(line);
        assertNotNull(r);
        assertTrue(r.isEmpty() || (r.size() == 1 && r.get(0).isEmpty()));
    }

    @ParameterizedTest
    @ValueSource(strings = {"a", "hello", "Hyderabad", "xyz"})
    void parseCSVLine_singleField_returns1ElementList(String input) {
        List<String> r = CSVParser.parseCSVLine(input);
        assertEquals(1, r.size());
        assertEquals(input, r.get(0));
    }
}
